def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        if ratio == 1:
            priorities[i] = 0
            continue
        score = 0
        for j in range(1, 21):
            if j % 3 == 0:
                term = ((-1) ** j) * (ratio ** j) / (j * 1.5)
            elif j % 2 == 0:
                term = (ratio ** (j/2)) / (j * 2)
            else:
                term = -((ratio ** j) / j)
            score += term
        adjustment = 1.0
        if capacity < item * 1.2:
            adjustment *= 3.0
        elif capacity < item * 1.5:
            adjustment *= 2.5
        elif capacity < item * 2:
            adjustment *= 1.8
        elif capacity < item * 3:
            adjustment *= 1.3
        score *= adjustment
        penalty = 0
        for k in range(max(0, i-2), min(n, i+3)):
            if bins[k] != 0 and k != i:
                overlap_ratio = item / bins[k]
                if 0 < overlap_ratio < 1:
                    penalty += (1 - overlap_ratio) ** 3
        penalty /= 5
        score = -score + penalty
        if score < 0:
            score = 0
        decay_score = 0
        for offset in range(1, 4):
            left_index = i - offset
            right_index = i + offset
            decay_factor = np.exp(-offset)
            if 0 <= left_index < n and bins[left_index] != 0:
                lr_ratio = item / bins[left_index]
                if lr_ratio < 1:
                    decay_score += decay_factor * (1 - lr_ratio)
            if 0 <= right_index < n and bins[right_index] != 0:
                rr_ratio = item / bins[right_index]
                if rr_ratio < 1:
                    decay_score += decay_factor * (1 - rr_ratio)
        decay_score /= 10
        final_score = score + decay_score
        if final_score < 0:
            final_score = 0
        priorities[i] = final_score
    return priorities
